        "@type": "ImageObject",
        "url": "https://midlandfloors.com/wp-content/uploads/2023/12/midland-small-logo.png"
      }
    },
    {
      "@type": "VideoObject",
      "@id": "https://midlandfloors.com/#video",
      "name": "What Helps You Drive More Sales",
      "description": "Our CEO shares proven strategies to help DC-area businesses boost revenue through smarter commercial floor care.",
      "thumbnailUrl": ["https://i.vimeocdn.com/video/replace-with-your-thumbnail.jpg"],
      "uploadDate": "2025-08-12T00:00:00-04:00",
      "duration": "PT2M30S",
      "embedUrl": "https://player.vimeo.com/video/916815779",
      "contentUrl": "https://vimeo.com/916815779",
      "publisher": { "@id": "https://midlandfloors.com/#organization" },
      "isPartOf": { "@id": "https://midlandfloors.com/#webpage" },
      "mainEntityOfPage": { "@id": "https://midlandfloors.com/#webpage" }
    },
    {
      "@type": "FAQPage",
      "@id": "https://midlandfloors.com/#faq",
      "mainEntityOfPage": { "@id": "https://midlandfloors.com/#webpage" },
      "mainEntity": [
        {
          "@type": "Question",
          "name": "How often should my commercial floors be maintained?",
          "acceptedAnswer": {
            "@type": "Answer",
            "text": "Frequency depends on traffic and flooring type—high-traffic lobbies may need daily cleaning, while offices or schools often require weekly maintenance, with deep cleanings scheduled semi-annually or annually."
          }
        },
        {
          "@type": "Question",
          "name": "Can you schedule floor care outside business hours?",
          "acceptedAnswer": {
            "@type": "Answer",
            "text": "Yes. We work evenings, weekends, or off-hours to minimize disruption to your operations."
          }
        },
        {
          "@type": "Question",
          "name": "Do you use eco-friendly cleaning products?",
          "acceptedAnswer": {
            "@type": "Answer",
            "text": "Yes. We offer green cleaning options using low-VOC or EPA-approved products wherever appropriate."
          }
        },
        {
          "@type": "Question",
          "name": "Are your technicians trained and insured?",
          "acceptedAnswer": {
            "@type": "Answer",
            "text": "Absolutely. All technicians undergo proper training, background checks, and coverage under full insurance for peace of mind."
          }
        },
        {
          "@type": "Question",
          "name": "Do I need a long-term contract for commercial floor care?",
          "acceptedAnswer": {
            "@type": "Answer",
            "text": "No. We offer flexible options—choose one-time services, recurring maintenance, or custom schedules tailored to your needs."
          }
        }
      ]
    }
  ]
}
</script>

